// ─────────────────────────────────────────────────────────────────────────────
// Static Search Implementation
// Uses the search_index.en.json generated by Zola at build time
// ─────────────────────────────────────────────────────────────────────────────

(function() {
  'use strict';

  // Theme toggle functionality
  const themeToggle = document.querySelector('.theme-toggle');
  if (themeToggle) {
    // Check for saved theme preference
    const savedTheme = localStorage.getItem('theme');
    if (savedTheme) {
      document.documentElement.setAttribute('data-theme', savedTheme);
    }

    themeToggle.addEventListener('click', () => {
      const currentTheme = document.documentElement.getAttribute('data-theme');
      const newTheme = currentTheme === 'dark' ? 'light' : 'dark';
      
      document.documentElement.setAttribute('data-theme', newTheme);
      localStorage.setItem('theme', newTheme);
    });
  }

  // Mobile navigation toggle
  const navToggle = document.querySelector('.nav-toggle');
  const siteNav = document.querySelector('.site-nav');
  
  if (navToggle && siteNav) {
    navToggle.addEventListener('click', () => {
      const isExpanded = navToggle.getAttribute('aria-expanded') === 'true';
      navToggle.setAttribute('aria-expanded', !isExpanded);
      siteNav.classList.toggle('is-open');
    });
  }

  // Search functionality (if you add a search input)
  let searchIndex = null;
  
  async function loadSearchIndex() {
    if (searchIndex) return searchIndex;
    
    try {
      const response = await fetch('/search_index.en.json');
      if (response.ok) {
        searchIndex = await response.json();
        return searchIndex;
      }
    } catch (error) {
      console.error('Failed to load search index:', error);
    }
    
    return null;
  }

  function searchContent(query, index) {
    if (!query || !index) return [];
    
    const queryLower = query.toLowerCase();
    const results = [];
    
    for (const item of index) {
      const titleMatch = item.title?.toLowerCase().includes(queryLower);
      const bodyMatch = item.body?.toLowerCase().includes(queryLower);
      const descMatch = item.description?.toLowerCase().includes(queryLower);
      
      if (titleMatch || bodyMatch || descMatch) {
        results.push({
          title: item.title,
          url: item.url,
          description: item.description || '',
          score: (titleMatch ? 10 : 0) + (descMatch ? 5 : 0) + (bodyMatch ? 1 : 0)
        });
      }
    }
    
    return results.sort((a, b) => b.score - a.score);
  }

  // Export for use in custom search implementations
  window.ZolaSearch = {
    loadIndex: loadSearchIndex,
    search: searchContent
  };

  // Smooth scroll for anchor links
  document.querySelectorAll('a[href^="#"]').forEach(anchor => {
    anchor.addEventListener('click', function(e) {
      const targetId = this.getAttribute('href').slice(1);
      const target = document.getElementById(targetId);
      
      if (target) {
        e.preventDefault();
        target.scrollIntoView({
          behavior: 'smooth',
          block: 'start'
        });
        
        // Update URL without scrolling
        history.pushState(null, null, `#${targetId}`);
      }
    });
  });

})();
